/// <summary>
/// Runs <c>nono profile groups &lt;name&gt; --json</c>, returns stdout or null.
/// Bounded by a 10-second timeout so a hung nono never freezes Settings.
/// Stderr is drained concurrently to prevent pipe-buffer deadlock.
/// </summary>
private static async Task<string?> RunNonoGroupAsync(
    string nonoBinary, string groupName, CancellationToken cancellationToken)
{
    try
    {
        var psi = new ProcessStartInfo
        {
            FileName = nonoBinary,
            RedirectStandardOutput = true,
            RedirectStandardError = true,
            UseShellExecute = false,
            CreateNoWindow = true,
        };
        psi.ArgumentList.Add("profile");
        psi.ArgumentList.Add("groups");
        psi.ArgumentList.Add(groupName);
        psi.ArgumentList.Add("--json");

        using var process = Process.Start(psi);
        if (process is null) return null;

        // Drain stderr concurrently to prevent pipe-buffer deadlock:
        // if nono writes enough to stderr (~4 KB) and nobody reads it,
        // the child process blocks on write and stdout never reaches EOF.
        var stderrTask = process.StandardError.ReadToEndAsync();

        // 10-second bounded timeout: a hung nono must not freeze Settings.
        using var timeoutCts = new CancellationTokenSource(TimeSpan.FromSeconds(10));
        using var linkedCts = CancellationTokenSource.CreateLinkedTokenSource(
            timeoutCts.Token, cancellationToken);

        string stdout;
        try
        {
            stdout = await process.StandardOutput.ReadToEndAsync(linkedCts.Token);
        }
        catch (OperationCanceledException)
        {
            // Propagate caller cancellation; treat our own timeout as unavailable.
            if (cancellationToken.IsCancellationRequested) throw;
            try { process.Kill(entireProcessTree: true); } catch { /* already exited */ }
            return null;
        }

        // Process wrote full stdout — drain stderr, then check exit code.
        await stderrTask;
        await process.WaitForExitAsync(CancellationToken.None);
        return process.ExitCode == 0 ? stdout : null;
    }
    catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested) { throw; }
    catch { return null; }
}
